    private static readonly Geometry OfficialGeometry = CreateGeometry(OfficialPath);
    private static readonly Geometry SteamWorkshopGeometry = CreateGeometry(SteamWorkshopPath);
    private static readonly Geometry LocalGeometry = CreateGeometry(LocalPath);

    public static Geometry GetIconGeometry(ModSource source) => source switch
    {
        ModSource.Official => OfficialGeometry,
        ModSource.SteamWorkshop => SteamWorkshopGeometry,
        _ => LocalGeometry
    };

    public static string GetShortLabel(ModSource source) => source switch
    {
        ModSource.Official => "OFFICIAL",
        ModSource.SteamWorkshop => "WORKSHOP",
        ModSource.Local => "LOCAL",
        ModSource.GitRepository => "GIT",
        ModSource.Decompiled => "DECOMPILED",
        _ => "UNKNOWN"
    };

    public static string GetDisplayName(ModSource source) => source switch
    {
        ModSource.Official => "Official RimWorld Content",
        ModSource.SteamWorkshop => "Steam Workshop Item",
        ModSource.Local => "Local Mod Files",
        ModSource.GitRepository => "Git Repository",
        ModSource.Decompiled => "Decompiled Content",
        _ => "Unknown Source"
    };

    public static string GetToolTip(ModSource source) => source switch
    {
        ModSource.Official => "Official RimWorld Content — Provided by Ludeon Studios.",
        ModSource.SteamWorkshop => "Steam Workshop Item — Installed from Steam Workshop.",
        ModSource.Local => "Local Mod Files — Installed outside Steam Workshop.",
        ModSource.GitRepository => "Git Repository — Sourced from a version-control repository.",
        ModSource.Decompiled => "Decompiled Content — Derived from an inspected assembly.",
        _ => "Unknown source."
    };

    private static Geometry CreateGeometry(string pathData)
    {
        var geometry = Geometry.Parse(pathData);
        if (geometry is PathGeometry pathGeometry)
        {
            pathGeometry.FillRule = FillRule.EvenOdd;
        }

        geometry.Freeze();
        return geometry;
    }
}
